import{_ as a,c as e,o as s,a1 as r}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"첫 실행: 데이터 디렉토리 이해 | Antigravity Tools","description":"Antigravity Tools의 데이터 디렉토리 위치 및 로그 관리를 학습합니다. 설정 페이지에서 데이터 디렉토리 열기, 로그 정리, 트레이 실행 및 시작 시 자동 시작을 마스터하고 두 가지 자동 시작 유형을 구별합니다.","frontmatter":{"title":"첫 실행: 데이터 디렉토리 이해 | Antigravity Tools","sidebarTitle":"데이터 디렉토리 찾기","subtitle":"첫 실행 필수: 데이터 디렉토리, 로그, 트레이 및 자동 시작","description":"Antigravity Tools의 데이터 디렉토리 위치 및 로그 관리를 학습합니다. 설정 페이지에서 데이터 디렉토리 열기, 로그 정리, 트레이 실행 및 시작 시 자동 시작을 마스터하고 두 가지 자동 시작 유형을 구별합니다.","tags":["첫 실행","데이터 디렉토리","로그","트레이","자동 시작"],"prerequisite":["start-getting-started","start-installation"],"order":3},"headers":[],"relativePath":"ko/lbjlaq/Antigravity-Manager/start/first-run-data/index.md","filePath":"ko/lbjlaq/Antigravity-Manager/start/first-run-data/index.md"}'),o={name:"ko/lbjlaq/Antigravity-Manager/start/first-run-data/index.md"};function i(d,t,l,n,c,h){return s(),e("div",null,[...t[0]||(t[0]=[r(`<h1 id="첫-실행-필수-데이터-디렉토리-로그-트레이-및-자동-시작" tabindex="-1">첫 실행 필수: 데이터 디렉토리, 로그, 트레이 및 자동 시작 <a class="header-anchor" href="#첫-실행-필수-데이터-디렉토리-로그-트레이-및-자동-시작" aria-label="Permalink to &quot;첫 실행 필수: 데이터 디렉토리, 로그, 트레이 및 자동 시작&quot;">​</a></h1><p>Antigravity Tools의 많은 &quot;마법처럼 보이는&quot; 능력(계정 풀, 할당량, 모니터링, 통계, 백그라운드 실행)은 결국 두 가지에 의존합니다: <strong>데이터 디렉토리</strong>와 <strong>로그</strong>. 처음 실행할 때 이 두 부분을 명확히 하면 나중에 문제 해결에 많은 시간을 절약할 수 있습니다.</p><h2 id="데이터-디렉토리란" tabindex="-1">데이터 디렉토리란? <a class="header-anchor" href="#데이터-디렉토리란" aria-label="Permalink to &quot;데이터 디렉토리란?&quot;">​</a></h2><p><strong>데이터 디렉토리</strong>는 Antigravity Tools가 로컬에 상태를 저장하는 폴더입니다: 계정 JSON, 할당량 관련 파일, 로그 파일, Token Stats/Proxy Monitor의 SQLite 데이터베이스가 모두 여기에 저장됩니다. 백업/마이그레이션/문제 해결을 할 때, 이 디렉토리를 먼저 찾으면 기본적으로 권위 있는 데이터 소스를 찾을 수 있습니다.</p><h2 id="학습-완료-후-가능한-작업" tabindex="-1">학습 완료 후 가능한 작업 <a class="header-anchor" href="#학습-완료-후-가능한-작업" aria-label="Permalink to &quot;학습 완료 후 가능한 작업&quot;">​</a></h2><ul><li>Antigravity Tools의 데이터 디렉토리 위치 파악 (한 번 클릭으로 열기)</li><li>백업할 파일과 로그/캐시 파일 구분</li><li>문제 해결이 필요할 때, 로그 및 모니터링 데이터베이스 빠르게 찾기</li><li>&quot;창 닫기&quot;와 &quot;프로그램 종료&quot;의 차이 이해 (트레이 상주)</li><li>두 가지 자동 시작 유형 구별: 시작 시 자동 시작 vs 역방향 프록시 자동 시작</li></ul><h2 id="현재-겪고-있는-문제" tabindex="-1">현재 겪고 있는 문제 <a class="header-anchor" href="#현재-겪고-있는-문제" aria-label="Permalink to &quot;현재 겪고 있는 문제&quot;">​</a></h2><ul><li>백업/마이그레이션을 하고 싶지만 계정이 정확히 어디에 저장되는지 모름</li><li>UI 오류/역방향 프록시 호출 실패지만 로그를 찾을 수 없음</li><li>창을 닫았는데 프로그램이 백그라운드에서 계속 실행 중인 줄 알았는데 실제로는 실행 중</li></ul><h2 id="이-기능을-언제-사용해야-할까" tabindex="-1">이 기능을 언제 사용해야 할까 <a class="header-anchor" href="#이-기능을-언제-사용해야-할까" aria-label="Permalink to &quot;이 기능을 언제 사용해야 할까&quot;">​</a></h2><ul><li>Antigravity Tools를 방금 설치하고 &quot;데이터가 어디에 있는지&quot; 확인하고 싶을 때</li><li>컴퓨터 교체/시스템 재설치 전, 계정 및 통계 데이터를 백업하고 싶을 때</li><li>OAuth 실패, 할당량 갱신 실패, 역방향 프록시 시작 실패, 401/429 호출 오류 해결이 필요할 때</li></ul><h2 id="🎒-시작-전-준비" tabindex="-1">🎒 시작 전 준비 <a class="header-anchor" href="#🎒-시작-전-준비" aria-label="Permalink to &quot;🎒 시작 전 준비&quot;">​</a></h2><ul><li>Antigravity Tools 설치 및 실행 가능한 상태</li><li>Settings 페이지에 진입 가능 (오른쪽 위/사이드바의 설정 진입점)</li><li>시스템 계정이 Home 디렉토리에 액세스할 권한이 있음</li></ul><div class="warning custom-block"><p class="custom-block-title">알림</p><p>이 수업에서는 어떤 파일이 &quot;진짜 데이터&quot;인지 알려주지만, 이러한 파일을 수동으로 편집하는 것은 권장하지 않습니다. 설정을 변경하려면 UI에서 우선 변경하세요.</p></div><h2 id="핵심-개념" tabindex="-1">핵심 개념 <a class="header-anchor" href="#핵심-개념" aria-label="Permalink to &quot;핵심 개념&quot;">​</a></h2><p>한 문장을 기억하세요:</p><p>&quot;<strong>데이터 디렉토리는 로컬 상태의 단일 진실 원천; 로그는 문제 해결의 첫 번째 진입점입니다.</strong>&quot;</p><p>Antigravity Tools는 Home 디렉토리 아래에 <code>.antigravity_tools</code> 데이터 디렉토리를 생성하고, 계정, 로그, 통계 데이터베이스 등의 내용을 모두 여기에 저장합니다 (디렉토리가 없으면 자동 생성).</p><p>동시에 기본적으로 트레이를 활성화합니다: 창을 닫으면 프로그램이 즉시 종료되지 않고 트레이에 숨겨진 채 백그라운드에서 계속 실행됩니다.</p><h2 id="함께-실습" tabindex="-1">함께 실습 <a class="header-anchor" href="#함께-실습" aria-label="Permalink to &quot;함께 실습&quot;">​</a></h2><h3 id="_1단계-설정-페이지에서-데이터-디렉토리-열기" tabindex="-1">1단계: 설정 페이지에서 데이터 디렉토리 열기 <a class="header-anchor" href="#_1단계-설정-페이지에서-데이터-디렉토리-열기" aria-label="Permalink to &quot;1단계: 설정 페이지에서 데이터 디렉토리 열기&quot;">​</a></h3><p><strong>이유</strong> 데이터 디렉토리 위치를 먼저 정확하게 파악하면, 이후 백업이나 문제 해결 시 &quot;목표&quot;가 있습니다.</p><p>Antigravity Tools에서 Settings를 열고 Advanced로 전환합니다.</p><p>&quot;데이터 디렉토리&quot;의 읽기 전용 입력 상자가 보입니다 (실제 경로 표시), 옆에 열기 버튼이 있습니다.</p><p>열기 버튼을 클릭합니다.</p><p><strong>예상 화면</strong>: 시스템 파일 관리자가 디렉토리를 엽니다, 경로는 <code>~/.antigravity_tools/</code>와 유사함.</p><h3 id="_2단계-데이터-디렉토리-경로-확인-크로스-플랫폼" tabindex="-1">2단계: 데이터 디렉토리 경로 확인 (크로스 플랫폼) <a class="header-anchor" href="#_2단계-데이터-디렉토리-경로-확인-크로스-플랫폼" aria-label="Permalink to &quot;2단계: 데이터 디렉토리 경로 확인 (크로스 플랫폼)&quot;">​</a></h3><p><strong>이유</strong> 나중에 백업 스크립트를 작성하거나 명령줄에서 문제 해결을 할 때, 시스템의 실제 경로를 알아야 합니다.</p><div class="vp-code-group vp-adaptive-theme"><div class="tabs"><input type="radio" name="group-cwrnl" id="tab-Hk_Wtor" checked><label data-title="macOS/Linux" for="tab-Hk_Wtor">macOS/Linux</label><input type="radio" name="group-cwrnl" id="tab-kgAoM_d"><label data-title="Windows" for="tab-kgAoM_d">Windows</label></div><div class="blocks"><div class="language-bash vp-adaptive-theme active"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">echo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$HOME</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/.antigravity_tools&quot;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ls</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -la</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$HOME</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/.antigravity_tools&quot;</span></span></code></pre></div><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$dataDir </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> Join-Path</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> $HOME</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;.antigravity_tools&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$dataDir</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Get-ChildItem</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Force $dataDir</span></span></code></pre></div></div></div><p><strong>예상 화면</strong>: 디렉토리가 존재함 (처음 설정 페이지를 열면 디렉토리가 자동으로 생성됨).</p><h3 id="_3단계-데이터-디렉토리-내의-핵심-파일-이해" tabindex="-1">3단계: 데이터 디렉토리 내의 &quot;핵심 파일&quot; 이해 <a class="header-anchor" href="#_3단계-데이터-디렉토리-내의-핵심-파일-이해" aria-label="Permalink to &quot;3단계: 데이터 디렉토리 내의 &quot;핵심 파일&quot; 이해&quot;">​</a></h3><p><strong>이유</strong> 모든 파일이 백업할 가치가 있는 것은 아닙니다. &quot;계정 데이터&quot;, &quot;통계 데이터베이스/로그&quot;를 먼저 구분하세요.</p><p>다음 파일 이름은 프로젝트 소스 코드에서 오며 모두 고정됨:</p><table tabindex="0"><thead><tr><th>보게 될 내용</th><th>용도</th><th>신경 써야 할 것</th></tr></thead><tbody><tr><td><code>accounts.json</code></td><td>계정 인덱스 (계정 목록/현재 계정 포함)</td><td>계정 마이그레이션 시 함께 백업 권장</td></tr><tr><td><code>accounts/</code></td><td>각 계정마다 하나의 <code>*.json</code> 파일</td><td>이것이 계정 데이터 본체</td></tr><tr><td><code>logs/</code></td><td>애플리케이션 로그 디렉토리</td><td>문제 해결 시 우선 확인</td></tr><tr><td><code>token_stats.db</code></td><td>Token Stats의 SQLite 데이터베이스</td><td>Token Stats 페이지의 데이터가 여기서 옴</td></tr><tr><td><code>proxy_logs.db</code></td><td>Proxy Monitor의 SQLite 데이터베이스</td><td>Monitor 페이지의 요청 로그가 여기서 옴</td></tr><tr><td><code>warmup_history.json</code></td><td>Smart Warmup의 로컬 기록</td><td>주로 중복 warmup 방지용</td></tr><tr><td><code>update_settings.json</code></td><td>업데이트 검사 설정 (자동 검사/간격 등)</td><td>일반적으로 수동 조작 필요 없음</td></tr></tbody></table><p><strong>예상 화면</strong>: 최소한 <code>logs/</code> 디렉토리가 존재함; 아직 계정을 추가하지 않았으면 <code>accounts.json</code>/<code>accounts/</code>가 아직 표시되지 않을 수 있음.</p><h3 id="_4단계-로그-위치-기억하기-문제-해결은-이것으로" tabindex="-1">4단계: 로그 위치 기억하기 (문제 해결은 이것으로) <a class="header-anchor" href="#_4단계-로그-위치-기억하기-문제-해결은-이것으로" aria-label="Permalink to &quot;4단계: 로그 위치 기억하기 (문제 해결은 이것으로)&quot;">​</a></h3><p><strong>이유</strong> UI의 오류 메시지는 보통 &quot;현상&quot;만 알려주고, 실제 실패 원인(예: 요청 실패, 파일 읽기/쓰기 실패)은 종종 로그에 있습니다.</p><p>Antigravity Tools는 로그를 데이터 디렉토리의 <code>logs/</code>에 작성합니다.</p><div class="vp-code-group vp-adaptive-theme"><div class="tabs"><input type="radio" name="group-cfnOF" id="tab-fm-Vgvn" checked><label data-title="macOS/Linux" for="tab-fm-Vgvn">macOS/Linux</label><input type="radio" name="group-cfnOF" id="tab-y_xRNlw"><label data-title="Windows" for="tab-y_xRNlw">Windows</label></div><div class="blocks"><div class="language-bash vp-adaptive-theme active"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ls</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -la</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$HOME</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/.antigravity_tools/logs&quot;</span></span></code></pre></div><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Get-ChildItem</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Force (</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Join-Path</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> $HOME</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;.antigravity_tools\\logs&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div></div></div><p><strong>예상 화면</strong>: 디렉토리 아래 일일별로 롤링되는 로그 파일이 존재함 (파일 이름은 <code>app.log</code>로 시작).</p><h3 id="_5단계-로그-정리-가-필요할-때-설정-페이지의-원-클릭-정리-사용" tabindex="-1">5단계: &quot;로그 정리&quot;가 필요할 때, 설정 페이지의 원 클릭 정리 사용 <a class="header-anchor" href="#_5단계-로그-정리-가-필요할-때-설정-페이지의-원-클릭-정리-사용" aria-label="Permalink to &quot;5단계: &quot;로그 정리&quot;가 필요할 때, 설정 페이지의 원 클릭 정리 사용&quot;">​</a></h3><p><strong>이유</strong> 어떤 문제는 한 번만 재현하고 그 로그를 따로 남기고 싶음; 이때 먼저 로그를 비우면 더 좋게 비교 가능.</p><p>Settings -&gt; Advanced에서 로그 영역을 찾고, &quot;로그 정리&quot; 클릭.</p><p><strong>예상 화면</strong>: 확인 대화상자 표시; 확인 후 정리 성공 메시지 표시.</p><div class="tip custom-block"><p class="custom-block-title">걱정할 두 가지</p><ul><li>로그는 자동으로 &quot;일일별 롤링&quot;되며, 시작 시 7일 이상의 구 로그를 정리하려고 시도합니다.</li><li>&quot;로그 정리&quot;는 로그 파일을 0바이트로 잘라, 실행 중인 프로세스가 동일한 파일 핸들에 계속 쓸 수 있게 합니다.</li></ul></div><h3 id="_6단계-창-닫기-와-프로그램-종료-의-차이-이해-트레이" tabindex="-1">6단계: &quot;창 닫기&quot;와 &quot;프로그램 종료&quot;의 차이 이해 (트레이) <a class="header-anchor" href="#_6단계-창-닫기-와-프로그램-종료-의-차이-이해-트레이" aria-label="Permalink to &quot;6단계: &quot;창 닫기&quot;와 &quot;프로그램 종료&quot;의 차이 이해 (트레이)&quot;">​</a></h3><p><strong>이유</strong> Antigravity Tools는 기본적으로 트레이를 활성화합니다; 창 오른쪽 위 닫기를 클릭하면 프로그램이 트레이에 숨겨진 채 계속 실행됩니다. 종료했다고 착각하면 &quot;포트 여전히 점유 중/백그라운드 여전히 실행 중&quot;의 착각이 발생하기 쉽습니다.</p><p>다음 작은 프로세스로 확인 가능:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>작업: 창 닫기 (종료 아님)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>┌─────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│  1단계                2단계                                 │</span></span>
<span class="line"><span>│  창 닫기 클릭    →   시스템 트레이/메뉴 바에서 아이콘 찾기    │</span></span>
<span class="line"><span>└─────────────────────────────────────────────────────────────┘</span></span>
<span class="line"><span></span></span>
<span class="line"><span>예상 화면: 트레이 아이콘이 여전히 존재하고, 클릭하면 창이 다시 표시됨.</span></span></code></pre></div><p>트레이 메뉴에는 UI를 거치지 않을 때 편리한 두 가지 자주 사용하는 작업이 있습니다:</p><ul><li>계정 전환: 다음 계정으로 전환</li><li>할당량 갱신: 현재 계정 할당량 갱신 (동시에 프론트엔드 표시 갱신 알림)</li></ul><h3 id="_7단계-시작-시-자동-시작-설정-시작-후-최소화" tabindex="-1">7단계: 시작 시 자동 시작 설정 (시작 후 최소화) <a class="header-anchor" href="#_7단계-시작-시-자동-시작-설정-시작-후-최소화" aria-label="Permalink to &quot;7단계: 시작 시 자동 시작 설정 (시작 후 최소화)&quot;">​</a></h3><p><strong>이유</strong> &quot;상주 서비스&quot;처럼 작동하기를 원하는 경우 (트레이 상주 + 백그라운드 갱신), 시작 시 자동 시작이 매번 수동으로 여는 것을 절약합니다.</p><p>Settings -&gt; General에서 &quot;시작 시 자동 시작&quot; 찾고, 활성화 선택.</p><p><strong>예상 화면</strong>: 전환 후 활성화 성공 메시지 표시; 다음 시작 시 <code>--minimized</code> 매개변수와 함께 실행됨.</p><div class="info custom-block"><p class="custom-block-title">두 가지 &quot;자동 시작&quot; 혼동 금지</p><table tabindex="0"><thead><tr><th>이름</th><th>의미</th><th>증거</th></tr></thead><tbody><tr><td>시작 시 자동 시작</td><td>컴퓨터 시작 후 Antigravity Tools 자동 시작 (데스크톱 애플리케이션 자체)</td><td>시작 매개변수에 <code>--minimized</code> 포함, <code>toggle_auto_launch</code> 명령 제공</td></tr><tr><td>역방향 프록시 자동 시작</td><td>Antigravity Tools 시작 후, <code>proxy.auto_start=true</code> 구성되면 로컬 역방향 프록시 서비스 자동 시작 시도</td><td>애플리케이션 시작 시 구성 읽기 및 <code>start_proxy_service(...)</code></td></tr></tbody></table></div><h2 id="체크포인트-✅" tabindex="-1">체크포인트 ✅ <a class="header-anchor" href="#체크포인트-✅" aria-label="Permalink to &quot;체크포인트 ✅&quot;">​</a></h2><ul><li>[ ] Settings -&gt; Advanced에서 데이터 디렉토리의 실제 경로 확인 가능</li><li>[ ] 데이터 디렉토리를 열고 대략적으로 <code>accounts.json</code>, <code>accounts/</code>, <code>logs/</code>, <code>token_stats.db</code>, <code>proxy_logs.db</code>를 인식</li><li>[ ] 로그가 <code>logs/</code> 아래에 있고 명령줄로 빠르게 보는 법 파악</li><li>[ ] 창 닫기 후 프로그램이 여전히 트레이에 있고, 종료하려면 트레이 Quit 사용</li><li>[ ] &quot;시작 시 자동 시작&quot;과 &quot;역방향 프록시 자동 시작&quot; 구별 가능</li></ul><h2 id="흔한-오류" tabindex="-1">흔한 오류 <a class="header-anchor" href="#흔한-오류" aria-label="Permalink to &quot;흔한 오류&quot;">​</a></h2><table tabindex="0"><thead><tr><th>시나리오</th><th>잘못된 방법 (❌)</th><th>권장 방법 (✓)</th></tr></thead><tbody><tr><td>데이터 디렉토리를 찾지 못함</td><td>시스템에서 앱 설치 디렉토리를 무작위 검색</td><td>Settings -&gt; Advanced에서 &quot;데이터 디렉토리&quot; 확인 및 한 번 클릭으로 열기</td></tr><tr><td>창 닫기 후 종료했다고 생각</td><td>창 닫기 후 설정/포트 변경</td><td>먼저 트레이 아이콘이 여전히 있는지 확인; 종료하려면 트레이 Quit 사용</td></tr><tr><td>로그가 너무 많아서 문제 해결 어려움</td><td>문제 재현 중 구 로그 뒤집기</td><td>먼저 &quot;로그 정리&quot; 후 재현 한 번, 마지막으로 이번 로그 파일만 확인</td></tr><tr><td>계정 데이터 변경하고 싶음</td><td><code>accounts/*.json</code> 수동 편집</td><td>UI의 가져오기/내보내기/마이그레이션 프로세스 사용 (다음 섹션 관련 장에서 설명)</td></tr></tbody></table><h2 id="이-수업-요약" tabindex="-1">이 수업 요약 <a class="header-anchor" href="#이-수업-요약" aria-label="Permalink to &quot;이 수업 요약&quot;">​</a></h2><ul><li>데이터 디렉토리는 Home 아래 <code>.antigravity_tools</code>에 고정 (macOS/Linux에서 보통 숨김 디렉토리로 표시), 계정/로그/통계 데이터베이스가 모두 여기에 있음</li><li>로그 디렉토리는 <code>logs/</code>, 문제 해결 시 우선 확인; 필요 시 설정 페이지에서 한 번 클릭 정리 가능</li><li>창 닫기는 트레이에 숨겨진 채 계속 실행; 완전히 종료하려면 트레이 Quit 사용</li><li>자동 시작에는 두 가지 유형: 시작 시 자동 시작 (애플리케이션) 및 역방향 프록시 자동 시작 (Proxy)</li></ul><hr><h2 id="다음-수업-예고" tabindex="-1">다음 수업 예고 <a class="header-anchor" href="#다음-수업-예고" aria-label="Permalink to &quot;다음 수업 예고&quot;">​</a></h2><blockquote><p>다음 수업에서 **<a href="./../add-account/">계정 추가: OAuth/Refresh Token 이중 채널과 모범 사례</a>**를 학습합니다.</p></blockquote><hr><h2 id="부록-소스-코드-참조" tabindex="-1">부록: 소스 코드 참조 <a class="header-anchor" href="#부록-소스-코드-참조" aria-label="Permalink to &quot;부록: 소스 코드 참조&quot;">​</a></h2><details><summary><strong>확장하여 소스 코드 위치 보기</strong></summary><blockquote><p>업데이트 시간: 2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>기능</th><th>파일 경로</th><th>행 번호</th></tr></thead><tbody><tr><td>데이터 디렉토리 위치 (<code>~/.antigravity_tools</code>)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/account.rs#L16-L33" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/account.rs</code></a></td><td>16-33</td></tr><tr><td>계정 인덱스 및 계정 파일 디렉토리 (<code>accounts.json</code> / <code>accounts/</code>)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/account.rs#L16-L46" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/account.rs</code></a></td><td>16-46</td></tr><tr><td>로그 디렉토리 및 일일별 롤링 (<code>logs/</code> + <code>app.log</code>)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/logger.rs#L17-L83" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/logger.rs</code></a></td><td>17-83</td></tr><tr><td>로그 정리 (파일 잘라내기)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/logger.rs#L149-L169" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/logger.rs</code></a></td><td>149-169</td></tr><tr><td>설정 페이지 데이터 디렉토리 표시 + 한 번 클릭 열기</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/pages/Settings.tsx#L525-L576" target="_blank" rel="noreferrer"><code>src/pages/Settings.tsx</code></a></td><td>525-576</td></tr><tr><td>설정 페이지 한 번 클릭 로그 정리 (버튼 + 대화상자 로직)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/pages/Settings.tsx#L127-L135" target="_blank" rel="noreferrer"><code>src/pages/Settings.tsx</code></a></td><td>127-135</td></tr><tr><td>설정 페이지 한 번 클릭 로그 정리 (Advanced 탭 버튼)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/pages/Settings.tsx#L732-L747" target="_blank" rel="noreferrer"><code>src/pages/Settings.tsx</code></a></td><td>732-747</td></tr><tr><td>트레이 메뉴 및 클릭 이벤트 (계정 전환/갱신/표시/종료)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/tray.rs#L9-L158" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/tray.rs</code></a></td><td>9-158</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>시작 시 자동 시작 스위치 (<code>toggle_auto_launch</code> / <code>is_auto_launch_enabled</code>)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/commands/autostart.rs#L4-L39" target="_blank" rel="noreferrer"><code>src-tauri/src/commands/autostart.rs</code></a></td><td>4-39</td></tr><tr><td>한 번 클릭 데이터 디렉토리 열기 / 경로 가져오기 / 로그 정리 명령</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/commands/mod.rs#L578-L621" target="_blank" rel="noreferrer"><code>src-tauri/src/commands/mod.rs</code></a></td><td>578-621</td></tr><tr><td>Token Stats 데이터베이스 파일명 (<code>token_stats.db</code>)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/token_stats.rs#L58-L61" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/token_stats.rs</code></a></td><td>58-61</td></tr><tr><td>Proxy Monitor 데이터베이스 파일명 (<code>proxy_logs.db</code>)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/proxy_db.rs#L5-L8" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/proxy_db.rs</code></a></td><td>5-8</td></tr><tr><td>Warmup 기록 파일명 (<code>warmup_history.json</code>)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/scheduler.rs#L14-L17" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/scheduler.rs</code></a></td><td>14-17</td></tr><tr><td>업데이트 설정 파일명 (<code>update_settings.json</code>)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/update_checker.rs#L150-L177" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/update_checker.rs</code></a></td><td>150-177</td></tr><tr><td>역방향 프록시 자동 시작 (<code>proxy.auto_start=true</code> 시 서비스 시작)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/lib.rs#L107-L126" target="_blank" rel="noreferrer"><code>src-tauri/src/lib.rs</code></a></td><td>107-126</td></tr></tbody></table></details><h2 id="다음-수업-예고-1" tabindex="-1">다음 수업 예고 <a class="header-anchor" href="#다음-수업-예고-1" aria-label="Permalink to &quot;다음 수업 예고&quot;">​</a></h2><blockquote><p>다음 수업에서 **<a href="./../add-account/">계정 추가: OAuth/Refresh Token 이중 채널과 모범 사례</a>**를 학습합니다.</p><p>배울 내용:</p><ul><li>OAuth를 언제 사용하고, 언제 refresh_token 직접 사용</li><li>콜백 실패 및 refresh_token을 얻지 못할 때 처리 방법</li><li>refresh_token 일괄 가져오기로 계정 풀 빠르게 구축</li></ul></blockquote>`,69)])])}const g=a(o,[["render",i]]);export{u as __pageData,g as default};
